class Solution
{
public:
bool solve(vector<int>& arr, vector<int>& freq)
{
    unordered_map<int, int> freqMap;
    for (int i = 0; i < arr.size(); i++) 
    {
        freqMap[arr[i]]++;
    }
    int left = 0, right = 0;
    int minLen = arr.size() + 1;
    while (left < arr.size() && right < arr.size())
    {
        if (freqMap.find(arr[left]) == freqMap.end())
        {
            left++;
        }
        else if (freqMap[arr[left]] + 1 != freq[left])
        {
            left++;
        }
        else
        {
            if (freqMap[arr[left]] == freq[left])
            {
                right = left + 1;
            }
            freqMap[arr[left]] = 0;
            left++;
            right++;
            minLen = min(minLen, right - left);
        }
    }
    return minLen == arr.size() + 1 ? -1 : minLen;
}
